SELECT performance_id, athlete_id, first_place, second_place, performance_date
FROM athlete_performance
WHERE league = 'NBA' AND season = '2023-2024';

SELECT athlete_name 
FROM athletes 
ORDER BY athlete_name ASC;

SELECT athlete_name
FROM athletes
WHERE date_of_birth = (SELECT MIN(date_of_birth) FROM athletes);

SELECT total_points
FROM athlete_performance
WHERE performance_id = 0;

SELECT points
FROM performance_ranking
WHERE place = 1;
